import{c as e,Q as r,j as a,m as l}from"./chunks/framework.BXc4yaFE.js";const k=JSON.parse('{"title":"Skills for Enterprise — 治理、安全審查與組織部署指南","description":"","frontmatter":{"title":"Skills for Enterprise — 治理、安全審查與組織部署指南","source":"https://platform.claude.com/docs/en/agents-and-tools/agent-skills/enterprise","type":"best-practices"},"headers":[],"relativePath":"research/best-practices/10-agent-skills-enterprise.md","filePath":"research/best-practices/10-agent-skills-enterprise.md","lastUpdated":1779894392000}'),d={name:"research/best-practices/10-agent-skills-enterprise.md"};function o(i,t,s,n,c,h){return r(),a("div",null,[...t[0]||(t[0]=[l(`<h1 id="skills-for-enterprise-—-治理、安全審查與組織部署指南" tabindex="-1">Skills for Enterprise — 治理、安全審查與組織部署指南 <a class="header-anchor" href="#skills-for-enterprise-—-治理、安全審查與組織部署指南" aria-label="Permalink to &quot;Skills for Enterprise — 治理、安全審查與組織部署指南&quot;">​</a></h1><blockquote><p>來源：<a href="https://platform.claude.com/docs/en/agents-and-tools/agent-skills/enterprise" target="_blank" rel="noreferrer">https://platform.claude.com/docs/en/agents-and-tools/agent-skills/enterprise</a><br> 收錄日期：2026-05-01<br> 涵蓋：安全審查、風險評估、生命週期管理、大規模組織、版本控制</p></blockquote><hr><h2 id="適用對象" tabindex="-1">適用對象 <a class="header-anchor" href="#適用對象" aria-label="Permalink to &quot;適用對象&quot;">​</a></h2><p>企業管理員和架構師，負責在組織內治理 Agent Skills。涵蓋審查、評估、部署、大規模管理。</p><hr><h2 id="安全審查與風險評估" tabindex="-1">安全審查與風險評估 <a class="header-anchor" href="#安全審查與風險評估" aria-label="Permalink to &quot;安全審查與風險評估&quot;">​</a></h2><h3 id="風險層級評估表" tabindex="-1">風險層級評估表 <a class="header-anchor" href="#風險層級評估表" aria-label="Permalink to &quot;風險層級評估表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>風險指標</th><th>查看內容</th><th>風險等級</th></tr></thead><tbody><tr><td><strong>Code execution</strong></td><td>Skill 目錄中有 <code>*.py</code>、<code>*.sh</code>、<code>*.js</code> 腳本</td><td>🔴 高：腳本可完整存取環境</td></tr><tr><td><strong>Instruction manipulation</strong></td><td>指令要求忽略安全規則、對用戶隱藏行動、條件改變行為</td><td>🔴 高：可繞過安全控制</td></tr><tr><td><strong>MCP server references</strong></td><td>引用 MCP tools（<code>ServerName:tool_name</code>）</td><td>🔴 高：延伸存取超出 Skill 本身</td></tr><tr><td><strong>Network access</strong></td><td>URL、API endpoint、<code>fetch</code>、<code>curl</code>、<code>requests</code> 呼叫</td><td>🔴 高：潛在資料外洩</td></tr><tr><td><strong>Hardcoded credentials</strong></td><td>Skill 檔案或腳本內有 API key、token、密碼</td><td>🔴 高：暴露於 Git 歷史和 context window</td></tr><tr><td><strong>File system scope</strong></td><td>Skill 目錄外的路徑、寬泛 glob、路徑穿越（<code>../</code>）</td><td>🟡 中</td></tr><tr><td><strong>Tool invocations</strong></td><td>指示 Claude 使用 bash、file operations 等 tool</td><td>🟡 中</td></tr></tbody></table><h3 id="審查-checklist" tabindex="-1">審查 Checklist <a class="header-anchor" href="#審查-checklist" aria-label="Permalink to &quot;審查 Checklist&quot;">​</a></h3><p>部署任何第三方或內部 Skill 前，完成以下步驟：</p><ol><li><strong>閱讀所有 Skill 目錄內容</strong>：SKILL.md、所有引用的 markdown 檔案、腳本</li><li><strong>驗證腳本行為符合描述</strong>：在沙箱環境執行腳本，確認輸出與 Skill description 一致</li><li><strong>檢查惡意指令</strong>：尋找要求忽略安全規則、對用戶隱藏行動、外洩資料、根據特定輸入改變行為的指令</li><li><strong>檢查外部 URL fetch 或網路呼叫</strong>：搜尋 <code>http</code>、<code>requests.get</code>、<code>urllib</code>、<code>curl</code>、<code>fetch</code></li><li><strong>確認無 hardcoded 憑證</strong>：憑證應使用環境變數或安全憑證存儲，不應出現在 Skill 內容中</li><li><strong>列出 Skill 指示 Claude 呼叫的工具</strong>：列出所有 bash 指令、file operations、tool 引用。評估組合風險（file-read + network 工具同時使用）</li><li><strong>確認 redirect 目的地</strong>：驗證外部 URL 指向預期域名</li><li><strong>確認無資料外洩模式</strong>：尋找讀取敏感資料後寫入、傳送或編碼到外部的指令</li></ol><blockquote><p>⚠️ <strong>絕不在完整稽核前部署未信任來源的 Skill</strong>。惡意 Skill 可指示 Claude 執行任意程式碼、存取敏感檔案或對外傳送資料。對待 Skill 安裝應與對待生產系統上安裝軟體同等嚴謹。</p></blockquote><hr><h2 id="部署前評估" tabindex="-1">部署前評估 <a class="header-anchor" href="#部署前評估" aria-label="Permalink to &quot;部署前評估&quot;">​</a></h2><h3 id="評估維度" tabindex="-1">評估維度 <a class="header-anchor" href="#評估維度" aria-label="Permalink to &quot;評估維度&quot;">​</a></h3><table tabindex="0"><thead><tr><th>維度</th><th>衡量內容</th><th>失敗範例</th></tr></thead><tbody><tr><td><strong>Triggering accuracy</strong></td><td>Skill 對正確查詢啟動，不相關查詢保持靜止？</td><td>Skill 對每次試算表提及都觸發，即使只是討論資料</td></tr><tr><td><strong>Isolation behavior</strong></td><td>Skill 單獨運作是否正常？</td><td>Skill 引用不存在於其目錄中的檔案</td></tr><tr><td><strong>Coexistence</strong></td><td>加入此 Skill 是否影響其他 Skill？</td><td>新 Skill description 太寬泛，搶奪其他 Skill 的觸發點</td></tr><tr><td><strong>Instruction following</strong></td><td>Claude 是否正確遵從 Skill 指令？</td><td>Claude 跳過驗證步驟或使用錯誤的 library</td></tr><tr><td><strong>Output quality</strong></td><td>Skill 產出是否正確有用？</td><td>生成的報告有格式錯誤或資料缺漏</td></tr></tbody></table><h3 id="評估要求" tabindex="-1">評估要求 <a class="header-anchor" href="#評估要求" aria-label="Permalink to &quot;評估要求&quot;">​</a></h3><ul><li>每個 Skill 提交 <strong>3–5 個代表性查詢</strong>的評估套件：應觸發的情況、不應觸發的情況、模糊邊界情況</li><li>跨組織使用的模型測試（Haiku、Sonnet、Opus）</li><li>詳細評估建立指引見 <code>06-agent-skills-best-practices.md</code> §評估與迭代</li></ul><h3 id="評估結果的決策依據" tabindex="-1">評估結果的決策依據 <a class="header-anchor" href="#評估結果的決策依據" aria-label="Permalink to &quot;評估結果的決策依據&quot;">​</a></h3><table tabindex="0"><thead><tr><th>訊號</th><th>行動</th></tr></thead><tbody><tr><td>Trigger accuracy 下降</td><td>更新 description 或指令</td></tr><tr><td>Coexistence 衝突</td><td>合併重疊 Skill 或縮窄 description</td></tr><tr><td>持續低輸出品質</td><td>重寫指令或加入驗證步驟</td></tr><tr><td>更新後持續失敗</td><td>廢棄此 Skill</td></tr></tbody></table><hr><h2 id="skill-生命週期管理" tabindex="-1">Skill 生命週期管理 <a class="header-anchor" href="#skill-生命週期管理" aria-label="Permalink to &quot;Skill 生命週期管理&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Plan → Create &amp; Review → Test → Deploy → Monitor → Iterate or Deprecate</span></span></code></pre></div><table tabindex="0"><thead><tr><th>階段</th><th>關鍵動作</th></tr></thead><tbody><tr><td><strong>Plan</strong></td><td>識別重複、易錯、需要專業知識的工作流程</td></tr><tr><td><strong>Create &amp; Review</strong></td><td>作者遵循最佳實踐；安全審查（使用上方 checklist）；提交評估套件；<strong>作者不應自我審查</strong></td></tr><tr><td><strong>Test</strong></td><td>單獨測試 + 與現有 Skill 共存測試；驗證 triggering accuracy、output quality、無回歸</td></tr><tr><td><strong>Deploy</strong></td><td>透過 Skills API 上傳（workspace 全員可用）；記錄到內部 registry（用途、擁有者、版本）</td></tr><tr><td><strong>Monitor</strong></td><td>追蹤使用模式、收集回饋；定期重跑評估偵測 drift；實作 application-level logging（API 目前不提供 analytics）</td></tr><tr><td><strong>Iterate or Deprecate</strong></td><td>新版本需通過完整評估套件；工作流程改變或評估分數下降 → 更新；評估持續失敗 → 廢棄</td></tr></tbody></table><hr><h2 id="大規模組織-skills" tabindex="-1">大規模組織 Skills <a class="header-anchor" href="#大規模組織-skills" aria-label="Permalink to &quot;大規模組織 Skills&quot;">​</a></h2><h3 id="召回率限制" tabindex="-1">召回率限制 <a class="header-anchor" href="#召回率限制" aria-label="Permalink to &quot;召回率限制&quot;">​</a></h3><p>同時載入的 Skills 數量過多 → Claude 可能無法選到正確的 Skill。每個 Skill 的 metadata 在 system prompt 中競爭注意力。</p><ul><li>使用評估套件衡量 recall accuracy，加入 Skill 時追蹤變化，效能下降就停止新增</li><li><strong>API 請求最多支援 8 個 Skills</strong>；若需更多，考慮合併或按任務類型路由不同 Skill 集</li></ul><h3 id="從小做起-再整合" tabindex="-1">從小做起，再整合 <a class="header-anchor" href="#從小做起-再整合" aria-label="Permalink to &quot;從小做起，再整合&quot;">​</a></h3><p>鼓勵從窄範圍的工作流程 Skill 開始，隨模式浮現再合併為角色型套件。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>開始：formatting-sales-reports, querying-pipeline-data, updating-crm-records</span></span>
<span class="line"><span>整合：sales-operations（用評估確認合併後效能等同個別 Skill）</span></span></code></pre></div><blockquote><p>只有當合併後 Skill 的評估確認效能等同被取代的個別 Skill，才合併。</p></blockquote><h3 id="內部-registry" tabindex="-1">內部 Registry <a class="header-anchor" href="#內部-registry" aria-label="Permalink to &quot;內部 Registry&quot;">​</a></h3><p>每個 Skill 記錄：</p><table tabindex="0"><thead><tr><th>欄位</th><th>內容</th></tr></thead><tbody><tr><td>Purpose</td><td>此 Skill 支援的工作流程</td></tr><tr><td>Owner</td><td>負責維護的團隊/個人</td></tr><tr><td>Version</td><td>目前部署版本</td></tr><tr><td>Dependencies</td><td>MCP servers、packages、外部服務</td></tr><tr><td>Evaluation status</td><td>最後評估日期與結果</td></tr></tbody></table><h3 id="角色型-skill-套件" tabindex="-1">角色型 Skill 套件 <a class="header-anchor" href="#角色型-skill-套件" aria-label="Permalink to &quot;角色型 Skill 套件&quot;">​</a></h3><table tabindex="0"><thead><tr><th>角色</th><th>Skill 範例</th></tr></thead><tbody><tr><td>Sales team</td><td>CRM 操作、pipeline 報告、提案生成</td></tr><tr><td>Engineering</td><td>Code review、部署工作流程、Incident response</td></tr><tr><td>Finance</td><td>報告生成、資料驗證、稽核準備</td></tr></tbody></table><hr><h2 id="版本控制與發布" tabindex="-1">版本控制與發布 <a class="header-anchor" href="#版本控制與發布" aria-label="Permalink to &quot;版本控制與發布&quot;">​</a></h2><h3 id="source-control" tabindex="-1">Source Control <a class="header-anchor" href="#source-control" aria-label="Permalink to &quot;Source Control&quot;">​</a></h3><p>Skill 目錄存放在 Git（SKILL.md + 所有 bundle 檔案 = 一個 Git-tracked 資料夾）：</p><ul><li>歷史追蹤</li><li>透過 PR 做 code review</li><li>回滾能力</li></ul><h3 id="版本策略" tabindex="-1">版本策略 <a class="header-anchor" href="#版本策略" aria-label="Permalink to &quot;版本策略&quot;">​</a></h3><table tabindex="0"><thead><tr><th>環境</th><th>策略</th></tr></thead><tbody><tr><td><strong>Production</strong></td><td>固定特定版本；升版前跑完整評估套件；每次更新都視為新部署並需完整安全審查</td></tr><tr><td><strong>Dev/Test</strong></td><td>使用最新版驗證變更</td></tr><tr><td><strong>Rollback</strong></td><td>保留前一版本備用；新版評估失敗 → 立即回退</td></tr></tbody></table><p><strong>Integrity verification</strong>：計算已審查 Skill 的 checksum 並在部署時驗證；使用 signed commits 確保來源可信。</p><h3 id="跨平台注意事項" tabindex="-1">跨平台注意事項 <a class="header-anchor" href="#跨平台注意事項" aria-label="Permalink to &quot;跨平台注意事項&quot;">​</a></h3><blockquote><p>⚠️ Custom Skills <strong>不跨平台同步</strong>：</p><ul><li>API 上傳的 Skills 在 claude.ai 和 Claude Code 上不可用</li><li>反之亦然</li></ul></blockquote><p>以 Git 作為 single source of truth，跨平台部署需自行實作同步流程。</p><hr><h2 id="快速參考-關鍵數字" tabindex="-1">快速參考：關鍵數字 <a class="header-anchor" href="#快速參考-關鍵數字" aria-label="Permalink to &quot;快速參考：關鍵數字&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指標</th><th>數值</th></tr></thead><tbody><tr><td>API 每請求最大 Skills 數</td><td>8</td></tr><tr><td>評估套件最小查詢數</td><td>3–5 個</td></tr><tr><td>Skill description 長度上限</td><td>1,024 字元</td></tr><tr><td>SKILL.md 建議長度上限</td><td>500 行</td></tr></tbody></table>`,53)])])}const g=e(d,[["render",o]]);export{k as __pageData,g as default};
